from flask import Flask, jsonify, request
from pymongo import MongoClient
import json

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management']
users = db['users']

@app.route('/get_user', methods=['GET'])
def get_user():
    user_id = request.args.get('user_id')
    if user_id:
        result = users.find_one({'_id': user_id})
        return jsonify(result)
    else:
        return jsonify({"error": "Missing required parameter: user_id"})

@app.route('/save_user', methods=['POST'])
def save_user():
    data = request.json
    if 'username' in data and 'email' in data:
        result = users.insert_one(data)
        return jsonify({'inserted_id': str(result.inserted_id)})
    else:
        return jsonify({"error": "Missing required parameter: username or email"})

@app.route('/aggregate', methods=['GET'])
def aggregate():
    pipeline = [{'$match': {'username': 'admin'}},
                {'$project': {'email': 1, '_id': 0}}]
    result = list(users.aggregate(pipeline))
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)